for food in foods:
    if food == 'cake':
        print(food, 'is high in sugar!')

Learn about classes, methods, and objects.
Code
class Person:
    def __init__(self, name, weight, height):
        self.name = name
        self.weight = weight
        self.height = height

    def bmi(self):
        return self.weight / (self.height ** 2)

p = Person('Alice', 68, 1.65)
print(p.name, p.bmi())

